final class PaymentRequestValidator {
    static void validate(PaymentRequest r) {
        if (r == null) throw new WebServiceException("Missing request");
        if (isBlank(r.getMerchantId())) throw new WebServiceException("Missing merchantId");
        if (isBlank(r.getPaymentMethod())) throw new WebServiceException("Missing paymentMethod");
        if (r.getAmount() == null) throw new WebServiceException("Missing amount");
        if (r.getAmount().compareTo(BigDecimal.ZERO) <= 0) throw new WebServiceException("Invalid amount");
        if (isBlank(r.getCurrency())) throw new WebServiceException("Missing currency");
        if (isBlank(r.getOrderId())) throw new WebServiceException("Missing orderId");
        if (r.getCurrency().length() != 3) throw new WebServiceException("Invalid currency");
    }

    private static boolean isBlank(String s) {
        return s == null || s.trim().isEmpty();
    }
}

